UPDATE app_notice
title = #{title}, content = #{content}, publisher_id = #{publisher_id}, status = #{status}, publish_time = #{publish_time}, update_time = now(),
WHERE id = #{id};

mapper.select:
SELECT  

,publisher_id.id as publisher_id_id1 
,publisher_id.USERNAME as publisher_id_USERNAME1 
,publisher_id.PASSWORD as publisher_id_PASSWORD1 
,publisher_id.NAME as publisher_id_NAME1 
,publisher_id.role_manage_id as publisher_id_role_manage_id1 
,publisher_id.create_time as publisher_id_create_time1 
,publisher_id.update_time as publisher_id_update_time1 
,publisher_id.signature as publisher_id_signature1 
FROM app_notice su

left join sys_user publisher_id on publisher_id.id=su.publisher_id
where 1 = 1
  and su.id = #{id}  
  and su.title = #{title}  
  and su.content = #{content}  
  and su.publisher_id = #{publisher_id}  
  and su.status = #{status}  
  and su.publish_time = #{publish_time}  
  and su.update_time = #{update_time}

